import "github.com/openmeterio/openmeter/pkg/treex"

type wrapper struct {
	name string
	node *treex.Node[*wrapper]
}

func newWrapper(name string) *wrapper {
	w := &wrapper{name: name}
	w.node = treex.NewNode(w) // value must be non-nil pointer
	return w
}

root, child := newWrapper("root"), newWrapper("child")
root.node.AddChild(child.node)
tr, err := treex.NewTree(root.node)
if err != nil { // ErrGraphHasCycle / ErrNodeGraphInvalid / ErrRootNodeIsNil
	return err
}
err = tr.DFS(func(n *treex.Node[*wrapper]) (bool, error) {
	_ = n.Value().name
	return false, nil
})
